import{_ as a,o as i,c as s,ai as t}from"./chunks/framework.CKB5fCPB.js";const y=JSON.parse('{"title":"Caddy setup","description":"","frontmatter":{},"headers":[],"relativePath":"network/Caddy Setup.md","filePath":"network/Caddy Setup.md"}'),d={name:"network/Caddy Setup.md"};function n(l,e,o,r,c,h){return i(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="caddy-setup" tabindex="-1">Caddy setup <a class="header-anchor" href="#caddy-setup" aria-label="Permalink to “Caddy setup”">​</a></h1><p>Caddy is basically a web server that automatically takes care of SSL/TLS and is pretty easy to use. If you dont use nginx already i recommend using caddy to anyone thats new to self hosting etc.</p><hr><h2 id="installing-caddy" tabindex="-1">Installing caddy <a class="header-anchor" href="#installing-caddy" aria-label="Permalink to “Installing caddy”">​</a></h2><p>The install instructions for caddy can be found <a href="https://caddyserver.com/docs/install" target="_blank" rel="noreferrer">on their website</a>. Basically it comes down to this for Linux Debian.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> caddy</span></span></code></pre></div><hr><h2 id="config-file" tabindex="-1">Config file <a class="header-anchor" href="#config-file" aria-label="Permalink to “Config file”">​</a></h2><p>Once installed you should have a config file called <code>Caddyfile</code> at this location <code>/etc/caddy/</code>, resulting in a path like <code>/etc/caddy/Caddyfile</code>. You can edit the config using nano or any other editor of your choice.</p><p>If you made changes to it you can reload caddy using the following commands.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">caddy</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --reload</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --config=/etc/caddy/Caddyfile</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># or alternatively</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reload</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> caddy</span></span></code></pre></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>On default there are already some configuration lines inside the caddy file. You can delete all of them if you dont need them, and if you only use it for DCTS i recommend removing those lines</p><p>When using the nano editor you can remove lines by pressing <code>CTRL + K</code>. To exit the editor you can press <code>CTRL + X</code>. If you made changes to the file you need to press <code>CTRL + X</code> , <code>Y</code> and <code>Enter</code> to save them.</p></div><hr><h2 id="reverse-proxies" tabindex="-1">Reverse Proxies <a class="header-anchor" href="#reverse-proxies" aria-label="Permalink to “Reverse Proxies”">​</a></h2><p>Now that caddy is installed you could setup some of the reverse proxies needed for DCTS. Example proxies can be found inside of <a href="./Reverse Proxy Setup">Reverse Proxy Setup</a>.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Cert files can usually be found at <code>/var/lib/caddy/.local/share/caddy/certificates/acme-v02.api.letsencrypt.org-directory/</code> which will be needed later for the livekit setup.</p></div>`,16)])])}const u=a(d,[["render",n]]);export{y as __pageData,u as default};
